import numpy as np
import pandas as pd
import statsmodels.api as sm
import statsmodels.formula.api as smf

def g_coefficient(acc):
    # 1. 还原你的数据结构
    list_s = [[f"S{s}", f"S{s}", f"S{s}"] for s in range(6, 16)]
    list_s_ = [item for sublist in list_s for item in sublist]
    
    list_e = [["E1", "E2", "E3"] for e in range(6, 16)]
    list_e_ = [item for sublist in list_e for item in sublist]
    
    df = pd.DataFrame({'Subject': list_s_, 'Measurement': list_e_, 'Score': acc})
    
    # 2. 拟合线性混合效应模型 (提取方差分量)
    # 截距项作为固定效应(即全局平均值)，Subject作为随机效应
    model = smf.mixedlm("Score ~ 1", df, groups=df["Subject"])
    result = model.fit()
    
    # 3. 提取方差分量
    grand_mean = result.fe_params['Intercept']          # 全局平均值
    var_s = float(result.cov_re.iloc[0, 0])             # 对象间方差 sigma^2_s
    var_e = result.scale                                # 剩余随机方差 sigma^2_e
    
    n = df['Subject'].nunique()                         # 对象数量 = 10
    e = df.groupby('Subject')['Measurement'].count().max() # 每个对象的测量次数 = 3
    
    # 4. 计算统计损害 (SEM) 与 全局可信度 (G 系数)
    var_grand_mean = (var_s / n) + (var_e / (n * e))    # 全局平均值的总方差
    sem_grand = np.sqrt(var_grand_mean)                 # 全局平均值的标准误
    
    # 根据概化理论 (G-Theory) 计算绝对可信度 G 系数
    G_absolute = var_s / (var_s + (var_s / n) + (var_e / (n * e)))
    
    # 计算95%置信区间
    ci_low = grand_mean - 1.96 * sem_grand
    ci_high = grand_mean + 1.96 * sem_grand
    
    # 5. 打印精美报告
    print(f"--- 统计学分析报告 ---")
    print(f"全局平均值 (Grand Mean): {grand_mean:.3f}%")
    print(f"对象间方差 (Sigma^2_s): {var_s:.3f}")
    print(f"剩余随机方差 (Sigma^2_e): {var_e:.3f}")
    print(f"全局平均值标准误 (SEM_grand - 量化损害): {sem_grand:.3f}")
    print(f"全局平均值 95% 置信区间 (95% CI): [{ci_low:.3f}%, {ci_high:.3f}%]")
    print(f"全局可信度 (G_absolute 系数): {G_absolute:.4f}")
    
    return G_absolute

